 78→fn toggle_window(window: &tauri::WebviewWindow) {
 79→    let visible = window.is_visible().unwrap_or(false);
 80→    let focused = window.is_focused().unwrap_or(false);
 81→
 82→    if visible && focused {
 83→        if let Err(e) = window.hide() {
 84→            eprintln!("failed to hide window: {e}");
 85→        }
 86→    } else if visible {
 87→        show_and_focus(window);
 88→    } else {
 89→        show_and_focus(window);
 90→    }
 91→}
