118→fn start_clipboard_monitor(app_handle: tauri::AppHandle) {
119→    use tauri_plugin_clipboard_manager::ClipboardExt;
120→
121→    std::thread::spawn(move || {
122→        let mut last_text = String::new();
123→
124→        loop {
125→            std::thread::sleep(Duration::from_millis(500));
126→
127→            let text = match app_handle.clipboard().read_text() {
128→                Ok(t) => t,
129→                Err(_) => continue,
130→            };
131→
132→            if text.is_empty() || text == last_text {
133→                continue;
134→            }
135→            last_text = text.clone();
136→
137→            let content_type = detect_content_type(&text);
138→
139→            let elapsed = std::time::SystemTime::now()
140→                .duration_since(std::time::UNIX_EPOCH)
141→                .unwrap_or_default();
142→            let timestamp_ms = elapsed.as_secs() * 1000 + elapsed.subsec_millis() as u64;
143→
144→            let payload = serde_json::json!({
145→                "content": text,
146→                "contentType": content_type,
147→                "timestamp": timestamp_ms,
148→            });
149→
150→            if let Err(e) = app_handle.emit("clipboard-changed", payload) {
151→                eprintln!("failed to emit clipboard-changed: {e}");
152→            }
153→        }
154→    });
155→}
