230→#[tauri::command(async)]
231→fn search_files(query: String, paths: Vec<String>, max_results: usize) -> Vec<FileEntryResult> {
232→    let max = if max_results == 0 { 200 } else { max_results };
233→    let query_lower = query.to_lowercase();
234→    let mut results: Vec<FileEntryResult> = Vec::new();
235→
236→    let search_paths: Vec<String> = if paths.is_empty() {
237→        if let Some(home) = dirs_next::home_dir() {
238→            let home_str = home.to_string_lossy().to_string();
239→            vec![
240→                format!("{home_str}/Documents"),
241→                format!("{home_str}/Downloads"),
242→                format!("{home_str}/Desktop"),
243→                format!("{home_str}/Projects"),
244→            ]
245→        } else {
246→            return results;
247→        }
248→    } else {
249→        paths
250→    };
251→
252→    for search_path in &search_paths {
253→        if results.len() >= max {
254→            break;
255→        }
256→
257→        let walker = WalkDir::new(search_path)
258→            .max_depth(5)
259→            .follow_links(false)
260→            .into_iter()
261→            .filter_entry(|entry| {
262→                let name = entry.file_name().to_string_lossy();
263→                if name.starts_with('.') && entry.depth() > 0 {
264→                    return false;
265→                }
266→                if entry.file_type().is_dir() && is_ignored_dir(&name) {
267→                    return false;
268→                }
269→                true
270→            });
271→
272→        for entry in walker.flatten() {
273→            if results.len() >= max {
274→                break;
275→            }
276→
277→            let name = entry.file_name().to_string_lossy().to_string();
278→
279→            if !query_lower.is_empty() && !name.to_lowercase().contains(&query_lower) {
280→                continue;
281→            }
282→
283→            if entry.depth() == 0 {
284→                continue;
285→            }
286→
287→            let path = entry.path();
288→            let metadata = match entry.metadata() {
289→                Ok(m) => m,
290→                Err(_) => continue,
291→            };
292→
293→            let size = metadata.len();
294→            let modified_at = metadata
295→                .modified()
296→                .ok()
297→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
298→                .map(|d| d.as_millis() as u64)
299→                .unwrap_or(0);
300→
301→            let file_type = detect_file_type(path);
302→            let path_str = path.to_string_lossy().to_string();
303→
304→            let id = format!("fs-{:x}", {
305→                use std::hash::{Hash, Hasher};
306→                let mut h = std::collections::hash_map::DefaultHasher::new();
307→                path_str.hash(&mut h);
308→                h.finish()
309→            });
310→
311→            results.push(FileEntryResult {
312→                id,
313→                name,
314→                path: path_str,
315→                file_type: file_type.to_string(),
316→                size,
317→                modified_at,
318→            });
319→        }
320→    }
321→
322→    results
323→}
