334→#[tauri::command]
335→fn reveal_in_finder(path: String) -> Result<(), String> {
336→    let p = std::path::Path::new(&path);
337→    if !is_path_within_home(p) {
338→        return Err(format!("path not allowed: {path}"));
339→    }
340→
341→    #[cfg(target_os = "macos")]
342→    {
343→        let output = std::process::Command::new("open")
344→            .arg("-R")
345→            .arg(&path)
346→            .output()
347→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
348→        if !output.status.success() {
349→            let stderr = String::from_utf8_lossy(&output.stderr);
350→            return Err(format!("failed to reveal {path}: {stderr}"));
351→        }
352→        return Ok(());
353→    }
354→
355→    #[cfg(target_os = "windows")]
356→    {
357→        let output = std::process::Command::new("explorer")
358→            .arg(format!("/select,{}", &path))
359→            .output()
360→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
361→        if !output.status.success() {
362→            let stderr = String::from_utf8_lossy(&output.stderr);
363→            return Err(format!("failed to reveal {path}: {stderr}"));
364→        }
365→        return Ok(());
366→    }
367→
368→    #[cfg(target_os = "linux")]
369→    {
370→        let parent = std::path::Path::new(&path)
371→            .parent()
372→            .map(|p| p.to_string_lossy().to_string())
373→            .unwrap_or_else(|| path.clone());
374→        let output = std::process::Command::new("xdg-open")
375→            .arg(&parent)
376→            .output()
377→            .map_err(|e| format!("failed to reveal: {e}"))?;
378→        if !output.status.success() {
379→            let stderr = String::from_utf8_lossy(&output.stderr);
380→            return Err(format!("failed to reveal: {stderr}"));
381→        }
382→        return Ok(());
383→    }
384→
385→    #[allow(unreachable_code)]
386→    Err("unsupported platform".to_string())
387→}
