438→fn extract_png_from_icns(icns_data: &[u8]) -> Option<Vec<u8>> {
439→    if icns_data.len() < 8 || &icns_data[0..4] != b"icns" {
440→        return None;
441→    }
442→
443→    let total_len = u32::from_be_bytes(icns_data[4..8].try_into().ok()?) as usize;
444→    let total_len = total_len.min(icns_data.len());
445→
446→    let preferred: &[&[u8; 4]] = &[
447→        b"icp5", b"icp6", b"icp4", b"ic07",
448→    ];
449→
450→    let mut offset = 8;
451→    let mut entries: Vec<(&[u8], &[u8])> = Vec::new();
452→
453→    while offset + 8 <= total_len {
454→        let type_code = &icns_data[offset..offset + 4];
455→        let entry_len = u32::from_be_bytes(icns_data[offset + 4..offset + 8].try_into().ok()?) as usize;
456→        if entry_len < 8 || offset + entry_len > total_len {
457→            break;
458→        }
459→        let data = &icns_data[offset + 8..offset + entry_len];
460→        entries.push((type_code, data));
461→        offset += entry_len;
462→    }
463→
464→    for pref in preferred {
465→        for (type_code, data) in &entries {
466→            if *type_code == pref.as_slice() && data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) {
467→                return Some(data.to_vec());
468→            }
469→        }
470→    }
471→
472→    let max_fallback_size = 200_000;
473→    for (_, data) in &entries {
474→        if data.starts_with(&[0x89, 0x50, 0x4E, 0x47]) && data.len() <= max_fallback_size {
475→            return Some(data.to_vec());
476→        }
477→    }
478→
479→    None
480→}
