482→fn extract_app_icon(app_path: &std::path::Path, dict: &plist::Dictionary) -> Option<String> {
483→    let icon_name = dict
484→        .get("CFBundleIconFile")
485→        .and_then(|v| v.as_string())
486→        .unwrap_or("AppIcon");
487→
488→    let icon_filename = if icon_name.ends_with(".icns") {
489→        icon_name.to_string()
490→    } else {
491→        format!("{icon_name}.icns")
492→    };
493→
494→    let icns_path = app_path.join("Contents/Resources").join(&icon_filename);
495→    let icns_data = std::fs::read(&icns_path).ok()?;
496→    let png_data = extract_png_from_icns(&icns_data)?;
497→
498→    Some(format!(
499→        "data:image/png;base64,{}",
500→        base64::engine::general_purpose::STANDARD.encode(&png_data)
501→    ))
502→}
