504→fn build_app_list() -> Vec<AppEntry> {
505→    let mut apps = Vec::new();
506→    let mut seen_paths = std::collections::HashSet::new();
507→
508→    let mut dirs = vec![std::path::PathBuf::from("/Applications")];
509→    if let Some(home) = dirs_next::home_dir() {
510→        dirs.push(home.join("Applications"));
511→    }
512→
513→    for dir in &dirs {
514→        for app_path in scan_app_dir(dir, 1) {
515→            let path_str = app_path.to_string_lossy().to_string();
516→            if !seen_paths.insert(path_str.clone()) {
517→                continue;
518→            }
519→
520→            let file_stem = app_path
521→                .file_stem()
522→                .map(|s| s.to_string_lossy().to_string())
523→                .unwrap_or_default();
524→
525→            let plist_dict = read_info_plist(&app_path);
526→            let name = plist_dict
527→                .as_ref()
528→                .and_then(display_name_from_plist)
529→                .unwrap_or_else(|| file_stem.clone());
530→            let icon = plist_dict
531→                .as_ref()
532→                .and_then(|dict| extract_app_icon(&app_path, dict));
533→
534→            let id = format!("app-{:x}", {
535→                use std::hash::{Hash, Hasher};
536→                let mut h = std::collections::hash_map::DefaultHasher::new();
537→                path_str.hash(&mut h);
538→                h.finish()
539→            });
540→
541→            apps.push(AppEntry {
542→                id,
543→                name,
544→                path: path_str,
545→                icon,
546→            });
547→        }
548→    }
549→
550→    apps.sort_by(|a, b| a.name.to_lowercase().cmp(&b.name.to_lowercase()));
551→    apps
552→}
