554→#[tauri::command(async)]
555→fn discover_applications(
556→    state: tauri::State<'_, Mutex<AppCache>>,
557→    force_refresh: bool,
558→) -> Vec<AppEntry> {
559→    if !force_refresh {
560→        if let Ok(cache) = state.lock() {
561→            if let Some(ref apps) = cache.apps {
562→                return apps.clone();
563→            }
564→        }
565→    }
566→
567→    let apps = build_app_list();
568→
569→    if let Ok(mut cache) = state.lock() {
570→        cache.apps = Some(apps.clone());
571→    }
572→
573→    apps
574→}
