576→fn is_valid_app_path(path: &std::path::Path) -> bool {
577→    let canonical = match path.canonicalize() {
578→        Ok(p) => p,
579→        Err(_) => return false,
580→    };
581→
582→    if canonical.extension().map_or(true, |e| e != "app") {
583→        return false;
584→    }
585→
586→    let mut allowed_dirs = vec![std::path::PathBuf::from("/Applications")];
587→    if let Some(home) = dirs_next::home_dir() {
588→        allowed_dirs.push(home.join("Applications"));
589→    }
590→
591→    for dir in &allowed_dirs {
592→        if let Ok(canonical_dir) = dir.canonicalize() {
593→            if canonical.starts_with(&canonical_dir) {
594→                return true;
595→            }
596→        }
597→    }
598→    false
599→}
